n = int(input())
numbers = []
for _ in range(n):
    numbers.append(int(input()))
count = {}
for x in numbers:
    count[x] = count.get(x, 0) + 1
best = min(count.keys())
for k in count:
    if count[k] > count[best] or (count[k] == count[best] and k < best):
        best = k
print(best)
